DarkRPUI = DarkRPUI or {}; DarkRPUI.UI = DarkRPUI.UI or {}
local UI = DarkRPUI.UI
function UI.RoundedBox(r,x,y,w,h,c) draw.RoundedBox(r or DarkRPUI.Util.Scale(10),x,y,w,h,c) end
function UI.Text(t,f,x,y,c,ax,ay) draw.SimpleText(t or "", f or "DarkRPUI.Body", x,y,c or DarkRPUI.Color("text"), ax or TEXT_ALIGN_LEFT, ay or TEXT_ALIGN_TOP) end
function UI.DrawBlur(panel, amount) if not DarkRPUI.Config.BlurEnabled then return end local x,y=panel:LocalToScreen(0,0); surface.SetDrawColor(255,255,255); surface.SetMaterial(Material("pp/blurscreen")); for i=1,3 do Material("pp/blurscreen"):SetFloat("$blur", (i/3)*(amount or 6)); Material("pp/blurscreen"):Recompute(); render.UpdateScreenEffectTexture(); surface.DrawTexturedRect(-x,-y,ScrW(),ScrH()) end end
function UI.StyleButton(btn, accent) btn:SetTextColor(DarkRPUI.Color("text")); btn:SetFont("DarkRPUI.Body"); btn.Paint=function(s,w,h) UI.RoundedBox(8,0,0,w,h, s:IsHovered() and (accent or DarkRPUI.Color("accent")) or DarkRPUI.Color("card")) end end
function UI.MakeHeader(parent, title, subtitle) local p=vgui.Create("DPanel",parent); p:SetTall(DarkRPUI.Util.Scale(72)); p.Paint=function(s,w,h) UI.Text(title,"DarkRPUI.Title",0,4,DarkRPUI.Color("text")); UI.Text(subtitle,"DarkRPUI.Small",2,42,DarkRPUI.Color("subtext")) end; return p end
function UI.MakeCard(parent, title, body, action) local c=vgui.Create("DButton",parent); c:SetText(""); c.Title=title; c.Body=body; c.DoClick=action or function() end; c.Paint=function(s,w,h) UI.RoundedBox(12,0,0,w,h,DarkRPUI.Color("card")); surface.SetDrawColor(DarkRPUI.Color(s:IsHovered() and "accent" or "border")); surface.DrawOutlinedRect(0,0,w,h,1); UI.Text(s.Title,"DarkRPUI.Subtitle",16,14); UI.Text(s.Body,"DarkRPUI.Small",16,42,DarkRPUI.Color("subtext")) end; return c end
